\.delegateResource(uint amount, uint resourceType) <p>Description: Delegate Bandwidth or Energy to the address.</p> <p>Params:</p> <ul> <li>amount — the amount of staked TRX corresponding to the resources to be delegated (unit: sun)</li> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: N/A</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    event ExpireUnfreezeWithdrew(uint);

    // the contract delegates 1 TRX bandwidth resource share to receiver
    function example(address payable receiver) external {
        receiver.delegateResource(1000000, 0);
        emit ResourceDelegated(1000000, 0, receiver);
    }

}
</code></pre>

\.unDelegateResource(amount, resourceType) <p>Description: Cancel the resource delegation to the address.</p> <p>Params:</p> <ul> <li>amount — the amount of staked TRX corresponding to the resources to be undelegated (unit: sun)</li> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: N/A</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    event ResourceUnDelegated(uint, uint, address);

    // the contract undelegates 1 TRX bandwidth resource share from the receiver
    function example(address payable receiver) external {
        receiver.unDelegateResource(1000000, 0);
        emit ResourceDelegated(1000000, 0, receiver);
    }
}
</code></pre>

Chain Properties <ul> <li>chain.totalNetLimit: total Bandwidth provision in the network (current value: 43,200,000,000)</li> <li>chain.totalNetWeight: total TRX staked for Bandwidth in the network (unit: TRX)</li> <li>chain.totalEnergyCurrentLimit: total Energy provision in the network (current value: 180,000,000,000)</li> <li>chain.totalEnergyWeight: total TRX staked for Energy in the network (unit: TRX)</li> <li>chain.unfreezeDelayDays: the unstaking pending period (unit: DAY, current value: 14 days)</li> </ul> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {

    function getChainParameters() view public returns(uint, uint, uint, uint, uint)       

    {
        return (chain.totalNetLimit, chain.totalNetWeight,
                chain.totalEnergyCurrentLimit, chain.totalEnergyWeight,
                chain.unfreezeDelayDays);
    }
}
</code></pre>

\.availableUnfreezeV2Size() returns(uint) <p>Description: Query the address' remaining times of executing the unstaking operation.</p> <p>Params:N/A</p> <p>Returns: remaining times of executing the unstaking operation</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function getvailableUnfreezeV2Size(address target) view public returns(uint) {
        return target.availableUnfreezeV2Size();
    }
}
</code></pre>

\.unfreezableBalanceV2() returns(uint amount) <p>Description: Query the unfreezable TRX balance corresponding to a specified resourceType under the address.</p> <p>Params:</p> <ul> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY" Returns: the unfreezable TRX balance (unit: sun)</li> </ul> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {

    function getvailableUnfreezeV2Size(address target) view public returns(uint amount) {
        return target.unfreezableBalanceV2(1);
    }
}
</code></pre>

\.expireUnfreezeBalanceV2(uint timestamp) returns(uint amount) <p>Description: Query the withdrawable balance of the address at the specified timestamp.</p> <p>Params:</p> <ul> <li>timestamp — the cut-off timestamp (unit: second)</li> </ul> <p>Returns: the withdrawable TRX balance (unit: sun)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {

    function getExpireUnfreezeBalanceV2(address target) view public returns(uint amount) {
        return target.expireUnfreezeBalanceV2(block.timestamp);
    }
}
</code></pre>

\.delegatableResource(uint resourceType) returns(uint amount) <p>Description: Query the delegatable resource share of the specified resourceType under the address.</p> <p>Params:</p> <ul> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: the delegatable resource share (unit: sun)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    //query the amount of delegatable resources share of energy for target address
    function getDelegatableResource(address target) view public returns(uint) {
        return target.delegatableResource(1);
    }
}
</code></pre>

\.resourceV2(address from, uint resourceType) returns(uint amount) <p>Description: Query the resource share of a specific resourceType delegated by a "from" address to the address.</p> <p>Params:</p> <ul> <li>from — the resource owner address</li> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: the resource share (unit: sun)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    //query the amount of resources share of energy delegated by a to b
    function getResourceV2(address b, address a) view public returns(uint) {
        return b.resourceV2(a, 1);
    }
}
</code></pre>

\.checkUnDelegateResource(uint amount, uint resourceTyp) returns(uint available, uint used, uint restoreTime) <p>Description: Query the resource shares of a specific resourceType that has been used and those available for recycling if delegation to the address is canceled.</p> <p>Params:</p> <ul> <li>amount — the resource share (unit: sun)</li> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: "available" indicates the amount of the available resource share, with sun as the unit. "used" indicates the amount of the used resource share, with sun as the unit. "restoreTime" indicates the restore time point for the used resources, with second as the unit.</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {

    function checkUnDelegateResource(address target) view public returns(uint, uint, uint) {
        (uint available, uint used, uint restoreTime) = target.checkUnDelegateResource(1000000, 1);
        return (available, used, restoreTime);
    }
}
</code></pre>

\.getResourceUsage(uint resourceTyp) returns(uint used, uint restoreTime) <p>Description: Query the resource usage of a specific resourceType by the address.</p> <p>Params:</p> <ul> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: "used" indicates the amount of the used resource share, with sun as the unit. "restoreTime" indicates the restore time point for the used resources, with second as the unit.</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {

    function getResourceUsage(address target) view public returns(uint, uint) {
        (uint used, uint restoreTime) = target.resourceUsage(1);
        return (used, restoreTime);
    }

}
</code></pre>

\.totalResource(uint resourceTyp) returns(uint amount) <p>Description: Query the total available resource share of a specific resourceType under the address.</p> <p>Params:</p> <ul> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: the amount of the available resource share (unit: sun)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    //query the available resource share of energy for the target address
    function getTotalResource(address target) view public returns(uint) {
        return target.totalResource(1);
    }

}
</code></pre>

\.totalDelegatedResource(uint resourceTyp) returns(uint amount) <p>Description: Query the resource share of a specific resourceType delegated by the address.</p> <p>Params:</p> <ul> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: the amount of the delegated resource share (unit: sun)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    //query the delegated resource share of energy for the target address
    function getTotalDelegatedResource(address from) view public returns(uint) {
        return from.totalDelegatedResource(1);
    }
}
</code></pre>

\.totalAcquiredResource(uint resourceType) returns(uint amount) <p>Description: Query the resource share of a specific resourceType delegated to the address.</p> <p>Params:</p> <ul> <li>resourceType — the resource type, with 0 for "BANDWIDTH" and 1 for "ENERGY"</li> </ul> <p>Returns: the amount of the acquired resource share (unit: sun)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    //query the acquired resource share of energy for the target address
    function getTotalAcquiredResource(address target) view public returns(uint) {
        return target.totalAcquiredResource(1);
    }
}
</code></pre>

vote(address[]  srList, uint[]  tpList) <p>Description: Vote for Super Representatives (SRs) in the <code>srList</code> array and every SR will get corresponding TPs as listed in the <code>tpList</code> array.</p> <p>Params:</p> <ul> <li><code>srList</code> — the SR list</li> <li><code>tpList</code> — the number of votes for SRs in srList</li> </ul> <p>Returns: N/A</p> <p>The following situations can cause the <code>revert</code> exception:</p> <ul> <li>Lengths of the<code>srList</code> array and the <code>tpList</code> array are different.</li> <li>The array length is greater than MAX_VOTE_NUMBER (30).</li> <li>There are non-SR addresses in the <code>srList</code> array.</li> <li>There are negative values in the 'tpList' array.</li> <li>Total TPs required are greater than the current TP balance of the contract.</li> </ul> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function voteWitness(address[] calldata srList, uint[] calldata tpList) external {
        vote(srList, tpList);
    }
}
</code></pre>

withdrawReward() returns(uint) <p>Description: Claim all voting rewards to the contract balance.</p> <p>Params:N/A</p> <p>Returns: the rewards claimed successfully (unit: sun)</p> <p>The following situations can cause the <code>revert</code> exception:</p> <ul> <li>The contract address is in the SR list of the genesis block.</li> <li>Sum of the contract balance and rewards overflow the value allowed for "long" (8 bytes).</li> </ul> <p>Example:c</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function withdrawReward() external returns(uint) {
        return withdrawreward();
    }
}
</code></pre>

rewardBalance() returns(uint) <p>Description: Query claimable rewards of the contract account.</p> <p>Params:N/A</p> <p>Returns: the claimable rewards of the contract account (unit: sun)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function queryRewardBalance() external view returns(uint) {
        return rewardBalance();
    }
}
</code></pre>

isSrCandidate(address sr) returns(bool) <p>Description: Query whether the address is an SR candidate address.</p> <p>Params:</p> <ul> <li><code>sr</code> - the target address</li> </ul> <p>Returns: If the address is an SR candidate address, <code>true</code> is returned. Otherwise,  <code>false</code> is returned.</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function isWitness(address sr) external view returns(bool) {
        return isSrCandidate(sr);
    }
}
</code></pre>

voteCount(address from, address to)  returns(uint) <p>Description: Query votes of the <code>from</code> account voting for the <code>to</code> account.</p> <p>Params:</p> <ul> <li><code>from</code> - the voting address</li> <li><code>to</code> - the SR address</li> </ul> <p>Returns: the corresponding votes (unit: TP, 1 TRX = 1 TP)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function queryVoteCount(address from, address to) external view returns(uint) {
        return voteCount(from, to);
    }
}
</code></pre>

usedVoteCount(address owner)  returns(uint) <p>Description: Query votes used by the address.</p> <p>Params:</p> <ul> <li><code>owner</code> - the target address</li> </ul> <p>Returns: the votes used by the <code>owner</code> account (unit: TP, 1 TRX = 1 TP)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function queryUsedVoteCount(address owner) external view returns(uint) {
        return usedVoteCount(owner);
    }
}
</code></pre>

ReceivedVoteCount(address owner)  returns(uint) <p>Description: Query votes received by the address.</p> <p>Params:</p> <ul> <li><code>owner</code> - the target address</li> </ul> <p>Returns: the votes received by the <code>owner</code> account (unit: TP, 1 TRX = 1 TP)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function queryReceivedVoteCount(address owner) external view returns(uint) {
        return receivedVoteCount(owner);
    }
}
</code></pre>

TotalVoteCount(address owner)  returns(uint) <p>Description: Query total votes owned by the address (also called TPs owned by the contract).</p> <p>Params:</p> <ul> <li><code>owner</code> - the target address</li> </ul> <p>Returns: total votes owned by the <code>owner</code> account (unit: TP, 1 TRX = 1 TP)</p> <p>Example:</p> <pre><code>pragma solidity ^0.8.17;

contract C {
    function queryTotalVoteCount(address owner) external view returns(uint) {
        return totalVoteCount(owner);
    }
}
</code></pre>
